import{_ as e,o as l,c as n,a2 as s}from"./chunks/framework.Pywvta2k.js";const f=JSON.parse('{"title":"京氏易八宫卦气与五脏","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/09-医易同源/08-京氏易八宫/01-八宫卦气与五脏.md","filePath":"tcm-data/09-医易同源/08-京氏易八宫/01-八宫卦气与五脏.md","lastUpdated":1781084559000}'),a={name:"tcm-data/09-医易同源/08-京氏易八宫/01-八宫卦气与五脏.md"};function d(g,t,r,i,o,x){return l(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="京氏易八宫卦气与五脏" tabindex="-1">京氏易八宫卦气与五脏 <a class="header-anchor" href="#京氏易八宫卦气与五脏" aria-label="Permalink to &quot;京氏易八宫卦气与五脏&quot;">​</a></h1><blockquote><p>京房（前77-前37年），西汉易学大家 八宫卦气说是&quot;卦气&quot;与&quot;人体气化&quot;对应的完整体系 比六十四卦的简单对应更深一层——揭示了五脏六腑的&quot;卦宫归属&quot;</p></blockquote><hr><h2 id="一、京房八宫体系" tabindex="-1">一、京房八宫体系 <a class="header-anchor" href="#一、京房八宫体系" aria-label="Permalink to &quot;一、京房八宫体系&quot;">​</a></h2><p>京房将六十四卦分为<strong>八宫</strong>，每宫八卦：</p><table tabindex="0"><thead><tr><th style="text-align:left;">宫</th><th style="text-align:left;">世爻</th><th style="text-align:left;">五行</th><th style="text-align:left;">人体对应</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>乾宫☰</strong></td><td style="text-align:left;">金</td><td style="text-align:left;">肺·大肠</td><td style="text-align:left;">神经·头·骨骼</td></tr><tr><td style="text-align:left;"><strong>兑宫☱</strong></td><td style="text-align:left;">金</td><td style="text-align:left;">肺·口</td><td style="text-align:left;">呼吸·声音·皮毛</td></tr><tr><td style="text-align:left;"><strong>离宫☲</strong></td><td style="text-align:left;">火</td><td style="text-align:left;">心·小肠</td><td style="text-align:left;">血脉·神志·目</td></tr><tr><td style="text-align:left;"><strong>震宫☳</strong></td><td style="text-align:left;">木</td><td style="text-align:left;">肝·胆</td><td style="text-align:left;">筋·愤怒·升发</td></tr><tr><td style="text-align:left;"><strong>巽宫☴</strong></td><td style="text-align:left;">木</td><td style="text-align:left;">肝·胆</td><td style="text-align:left;">风·疏泄·入</td></tr><tr><td style="text-align:left;"><strong>坎宫☵</strong></td><td style="text-align:left;">水</td><td style="text-align:left;">肾·膀胱</td><td style="text-align:left;">骨·恐·封藏</td></tr><tr><td style="text-align:left;"><strong>艮宫☶</strong></td><td style="text-align:left;">土</td><td style="text-align:left;">胃·脾</td><td style="text-align:left;">止·纳·肌肉</td></tr><tr><td style="text-align:left;"><strong>坤宫☷</strong></td><td style="text-align:left;">土</td><td style="text-align:left;">脾·胃</td><td style="text-align:left;">运化·容·腹</td></tr></tbody></table><hr><h2 id="二、八宫卦气与五脏生理" tabindex="-1">二、八宫卦气与五脏生理 <a class="header-anchor" href="#二、八宫卦气与五脏生理" aria-label="Permalink to &quot;二、八宫卦气与五脏生理&quot;">​</a></h2><h3 id="乾宫-金-——肺与大肠" tabindex="-1">乾宫（金）——肺与大肠 <a class="header-anchor" href="#乾宫-金-——肺与大肠" aria-label="Permalink to &quot;乾宫（金）——肺与大肠&quot;">​</a></h3><p><strong>宫属</strong>：金，纯阳之宫 <strong>生理</strong>：肺主气、司呼吸，与大肠相表里</p><table tabindex="0"><thead><tr><th style="text-align:left;">本宫卦</th><th style="text-align:left;">一世</th><th style="text-align:left;">二世</th><th style="text-align:left;">三世</th><th style="text-align:left;">四世</th><th style="text-align:left;">五世</th><th style="text-align:left;">游魂</th><th style="text-align:left;">归魂</th></tr></thead><tbody><tr><td style="text-align:left;">乾䷀</td><td style="text-align:left;">姤䷫</td><td style="text-align:left;">遁䷠</td><td style="text-align:left;">否䷋</td><td style="text-align:left;">观䷓</td><td style="text-align:left;">剥䷖</td><td style="text-align:left;">晋䷢</td><td style="text-align:left;">大有䷍</td></tr></tbody></table><p><strong>相关</strong>：</p><ul><li>乾宫否䷋ = 天地不交 → 上热下寒</li><li>患者的头前倾 = 乾阳不足 → 督脉失养</li></ul><p><strong>用药</strong>：百合（乾宫）、黄芪（补金气）</p><hr><h3 id="兑宫-金-——肺与口鼻" tabindex="-1">兑宫（金）——肺与口鼻 <a class="header-anchor" href="#兑宫-金-——肺与口鼻" aria-label="Permalink to &quot;兑宫（金）——肺与口鼻&quot;">​</a></h3><p><strong>宫属</strong>：金，阴宫 <strong>生理</strong>：肺开窍于鼻，在声为哭</p><table tabindex="0"><thead><tr><th style="text-align:left;">本宫卦</th><th style="text-align:left;">一世</th><th style="text-align:left;">二世</th><th style="text-align:left;">三世</th><th style="text-align:left;">四世</th><th style="text-align:left;">五世</th><th style="text-align:left;">游魂</th><th style="text-align:left;">归魂</th></tr></thead><tbody><tr><td style="text-align:left;">兑䷹</td><td style="text-align:left;">困䷮</td><td style="text-align:left;">萃䷬</td><td style="text-align:left;">咸䷞</td><td style="text-align:left;">蹇䷦</td><td style="text-align:left;">谦䷎</td><td style="text-align:left;">小过䷽</td><td style="text-align:left;">归妹䷵</td></tr></tbody></table><p><strong>相关</strong>：4月鼻疮→兑宫之病 <strong>相关</strong>：口干舌燥+打鼾→兑宫之病（口鼻不畅）</p><p><strong>用药</strong>：麦冬、五味子（兑宫润）</p><hr><h3 id="离宫-火-——心与小肠" tabindex="-1">离宫（火）——心与小肠 <a class="header-anchor" href="#离宫-火-——心与小肠" aria-label="Permalink to &quot;离宫（火）——心与小肠&quot;">​</a></h3><p><strong>宫属</strong>：火，阴宫 <strong>生理</strong>：心主血脉、主神志，小肠泌别清浊</p><table tabindex="0"><thead><tr><th style="text-align:left;">本宫卦</th><th style="text-align:left;">一世</th><th style="text-align:left;">二世</th><th style="text-align:left;">三世</th><th style="text-align:left;">四世</th><th style="text-align:left;">五世</th><th style="text-align:left;">游魂</th><th style="text-align:left;">归魂</th></tr></thead><tbody><tr><td style="text-align:left;">离䷝</td><td style="text-align:left;">旅䷷</td><td style="text-align:left;">鼎䷱</td><td style="text-align:left;">未济䷿</td><td style="text-align:left;">蒙䷃</td><td style="text-align:left;">涣䷺</td><td style="text-align:left;"><strong>讼</strong>䷅</td><td style="text-align:left;"><strong>同人</strong>䷌</td></tr></tbody></table><p><strong>相关</strong>：</p><ul><li>⭐ <strong>离宫未济䷿</strong> = 火在上、水在下 → 上热下寒 → <strong>患者（男）核心病机</strong></li><li><strong>离宫讼䷅</strong> = 天水违行 → 水火不交</li></ul><p><strong>相关</strong>：</p><ul><li>潮热烦躁→离火浮越</li><li>入睡困难→离火不降</li></ul><p><strong>用药</strong>：龙骨、牡蛎（降离火）、黄连（清离热）、酸枣仁（养离阴）</p><p><strong>特别：坎离交济法</strong></p><ul><li>患者处方：附子（温坎）+ 龙骨（降离）= <strong>坎离交济</strong></li><li>这就是金鼎汤（降离）+ 天魂汤（升坎）的卦气医理</li></ul><hr><h3 id="震宫-木-——肝与胆" tabindex="-1">震宫（木）——肝与胆 <a class="header-anchor" href="#震宫-木-——肝与胆" aria-label="Permalink to &quot;震宫（木）——肝与胆&quot;">​</a></h3><p><strong>宫属</strong>：木，阳宫 <strong>生理</strong>：肝主疏泄、藏血，胆主决断</p><table tabindex="0"><thead><tr><th style="text-align:left;">本宫卦</th><th style="text-align:left;">一世</th><th style="text-align:left;">二世</th><th style="text-align:left;">三世</th><th style="text-align:left;">四世</th><th style="text-align:left;">五世</th><th style="text-align:left;">游魂</th><th style="text-align:left;">归魂</th></tr></thead><tbody><tr><td style="text-align:left;">震䷲</td><td style="text-align:left;">豫䷏</td><td style="text-align:left;">解䷧</td><td style="text-align:left;">恒䷟</td><td style="text-align:left;">升䷭</td><td style="text-align:left;">井䷯</td><td style="text-align:left;">大过䷛</td><td style="text-align:left;">随䷐</td></tr></tbody></table><p><strong>相关</strong>：</p><ul><li>震宫解䷧ = 雷水解 → 寒湿得化 → 苓桂术甘汤的卦象</li><li>肝郁不能升发→目干涩、抽筋</li></ul><p><strong>用药</strong>：桂枝（升震阳）、白芍（敛震阴）、柴胡（疏震郁）</p><hr><h3 id="巽宫-木-——胆与三焦" tabindex="-1">巽宫（木）——胆与三焦 <a class="header-anchor" href="#巽宫-木-——胆与三焦" aria-label="Permalink to &quot;巽宫（木）——胆与三焦&quot;">​</a></h3><p><strong>宫属</strong>：木，阴宫 <strong>生理</strong>：胆主决断，三焦通行气水</p><table tabindex="0"><thead><tr><th style="text-align:left;">本宫卦</th><th style="text-align:left;">一世</th><th style="text-align:left;">二世</th><th style="text-align:left;">三世</th><th style="text-align:left;">四世</th><th style="text-align:left;">五世</th><th style="text-align:left;">游魂</th><th style="text-align:left;">归魂</th></tr></thead><tbody><tr><td style="text-align:left;">巽䷸</td><td style="text-align:left;">小畜䷈</td><td style="text-align:left;">家人䷤</td><td style="text-align:left;">益䷩</td><td style="text-align:left;">无妄䷘</td><td style="text-align:left;">噬嗑䷔</td><td style="text-align:left;">颐䷚</td><td style="text-align:left;"><strong>蛊</strong>䷑</td></tr></tbody></table><p><strong>相关</strong>：</p><ul><li>巽宫蛊䷑ = 山下有风 → 肝气犯胃 → 饭后腹胀</li><li>胆气不疏→情绪烦躁</li></ul><p><strong>用药</strong>：柴胡（巽宫主药）</p><hr><h3 id="坎宫-水-——肾与膀胱" tabindex="-1">坎宫（水）——肾与膀胱 <a class="header-anchor" href="#坎宫-水-——肾与膀胱" aria-label="Permalink to &quot;坎宫（水）——肾与膀胱&quot;">​</a></h3><p><strong>宫属</strong>：水，阳宫 <strong>生理</strong>：肾藏精、主水，膀胱气化</p><table tabindex="0"><thead><tr><th style="text-align:left;">本宫卦</th><th style="text-align:left;">一世</th><th style="text-align:left;">二世</th><th style="text-align:left;">三世</th><th style="text-align:left;">四世</th><th style="text-align:left;">五世</th><th style="text-align:left;">游魂</th><th style="text-align:left;">归魂</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>坎</strong>䷜</td><td style="text-align:left;"><strong>节</strong>䷻</td><td style="text-align:left;"><strong>屯</strong>䷂</td><td style="text-align:left;"><strong>既济</strong>䷾</td><td style="text-align:left;"><strong>革</strong>䷰</td><td style="text-align:left;"><strong>丰</strong>䷶</td><td style="text-align:left;"><strong>明夷</strong>䷣</td><td style="text-align:left;"><strong>师</strong>䷆</td></tr></tbody></table><p><strong>相关</strong>：</p><ul><li>⭐ <strong>坎宫为本宫！</strong> 患者的根本在坎水寒</li><li><strong>坎宫卦序揭示了肾病的传变路径</strong>： <ul><li>坎水寒（坎䷜）→ 水停不行（节䷻）→ 水寒木郁（屯䷂）→ 治疗目标是既济䷾</li></ul></li><li><strong>坎宫游魂明夷䷣</strong> = 热被水困 → 患者（男）口渴不贪凉正是明夷卦</li></ul><p><strong>用药</strong>：附子（补坎阳）、茯苓泽泻（利坎水）、黄柏（清坎热）</p><hr><h3 id="艮宫-土-——胃" tabindex="-1">艮宫（土）——胃 <a class="header-anchor" href="#艮宫-土-——胃" aria-label="Permalink to &quot;艮宫（土）——胃&quot;">​</a></h3><p><strong>宫属</strong>：土，阳宫 <strong>生理</strong>：胃主受纳、腐熟水谷</p><table tabindex="0"><thead><tr><th style="text-align:left;">本宫卦</th><th style="text-align:left;">一世</th><th style="text-align:left;">二世</th><th style="text-align:left;">三世</th><th style="text-align:left;">四世</th><th style="text-align:left;">五世</th><th style="text-align:left;">游魂</th><th style="text-align:left;">归魂</th></tr></thead><tbody><tr><td style="text-align:left;">艮䷳</td><td style="text-align:left;">贲䷕</td><td style="text-align:left;">大畜䷙</td><td style="text-align:left;">损䷨</td><td style="text-align:left;">睽䷥</td><td style="text-align:left;">履䷉</td><td style="text-align:left;">中孚䷼</td><td style="text-align:left;">渐䷴</td></tr></tbody></table><p><strong>相关</strong>：</p><ul><li>胃虚则纳差、腹胀→艮宫之病</li></ul><p><strong>用药</strong>：砂仁（温艮阳）、枳实（破艮滞）</p><hr><h3 id="坤宫-土-——脾" tabindex="-1">坤宫（土）——脾 <a class="header-anchor" href="#坤宫-土-——脾" aria-label="Permalink to &quot;坤宫（土）——脾&quot;">​</a></h3><p><strong>宫属</strong>：土，阴宫 <strong>生理</strong>：脾主运化、升清、统血</p><table tabindex="0"><thead><tr><th style="text-align:left;">本宫卦</th><th style="text-align:left;">一世</th><th style="text-align:left;">二世</th><th style="text-align:left;">三世</th><th style="text-align:left;">四世</th><th style="text-align:left;">五世</th><th style="text-align:left;">游魂</th><th style="text-align:left;">归魂</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>坤</strong>䷁</td><td style="text-align:left;"><strong>复</strong>䷗</td><td style="text-align:left;"><strong>临</strong>䷒</td><td style="text-align:left;"><strong>泰</strong>䷊</td><td style="text-align:left;"><strong>大壮</strong>䷡</td><td style="text-align:left;"><strong>夬</strong>䷪</td><td style="text-align:left;"><strong>需</strong>䷄</td><td style="text-align:left;"><strong>比</strong>䷇</td></tr></tbody></table><p><strong>不同类型患者相关</strong>：</p><ul><li>⭐ <strong>坤宫第二</strong>——脾土是两人都涉及的核心</li><li>坤宫复䷗ = 一阳来复 → 附子温阳的卦象</li><li>坤宫泰䷊ = 三阳开泰 → <strong>治疗目标！</strong></li><li>坤宫需䷄ = 云上于天 → 阳气被水湿所阻</li></ul><p><strong>用药</strong>：人参（补坤土）、白术（燥坤湿）、茯苓（泻坤湿）、干姜（温坤寒）</p><hr><h2 id="三、八宫卦气病传模型-京房→黄元御" tabindex="-1">三、八宫卦气病传模型（京房→黄元御） <a class="header-anchor" href="#三、八宫卦气病传模型-京房→黄元御" aria-label="Permalink to &quot;三、八宫卦气病传模型（京房→黄元御）&quot;">​</a></h2><p>京房的八宫卦气说，与黄元御的&quot;一气周流&quot;惊人地对应：</p><h3 id="黄元御的-水寒土湿木郁-坎宫-坤宫-震宫" tabindex="-1">黄元御的&quot;水寒土湿木郁&quot;=坎宫+坤宫+震宫 <a class="header-anchor" href="#黄元御的-水寒土湿木郁-坎宫-坤宫-震宫" aria-label="Permalink to &quot;黄元御的&quot;水寒土湿木郁&quot;=坎宫+坤宫+震宫&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">黄元御病机</th><th style="text-align:left;">京房八宫</th><th style="text-align:left;">对应良方</th><th style="text-align:left;">患者症状</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>水寒</strong></td><td style="text-align:left;">⭐ <strong>坎宫</strong></td><td style="text-align:left;">附子（温坎阳）</td><td style="text-align:left;">腰凉、脚冷</td></tr><tr><td style="text-align:left;"><strong>土湿</strong></td><td style="text-align:left;">⭐ <strong>坤宫</strong></td><td style="text-align:left;">茯苓（泄坤湿）</td><td style="text-align:left;">面暗、阴囊湿</td></tr><tr><td style="text-align:left;"><strong>木郁</strong></td><td style="text-align:left;">⭐ <strong>震宫</strong></td><td style="text-align:left;">桂枝（升震阳）</td><td style="text-align:left;">目干、抽筋</td></tr><tr><td style="text-align:left;"><strong>相火不降</strong></td><td style="text-align:left;"><strong>离宫</strong></td><td style="text-align:left;">龙骨（降离火）</td><td style="text-align:left;">前胸出汗</td></tr></tbody></table><h3 id="治疗路径的八宫卦气解释" tabindex="-1">治疗路径的八宫卦气解释 <a class="header-anchor" href="#治疗路径的八宫卦气解释" aria-label="Permalink to &quot;治疗路径的八宫卦气解释&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>当前：  坎宫寒 + 坤宫湿 + 离宫浮 = 未济䷿</span></span>
<span class="line"><span>         ↓</span></span>
<span class="line"><span>第一步：温坎阳（附子）→ 调整坎宫</span></span>
<span class="line"><span>         ↓</span></span>
<span class="line"><span>第二步：泄坤湿（茯苓泽泻）→ 调整坤宫</span></span>
<span class="line"><span>         ↓</span></span>
<span class="line"><span>第三步：升震木（桂枝）→ 调整震宫</span></span>
<span class="line"><span>         ↓</span></span>
<span class="line"><span>第四步：降离火（龙牡白芍）→ 调整离宫</span></span>
<span class="line"><span>         ↓</span></span>
<span class="line"><span>最终：  四宫归位 → 既济䷾</span></span></code></pre></div><hr><h2 id="四、用药的八宫法则" tabindex="-1">四、用药的八宫法则 <a class="header-anchor" href="#四、用药的八宫法则" aria-label="Permalink to &quot;四、用药的八宫法则&quot;">​</a></h2><p><strong>每个药都属于一个卦宫</strong>，用药就是调宫：</p><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:left;">归宫</th><th style="text-align:left;">入药部位</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>附子</strong></td><td style="text-align:left;">坎宫+乾宫</td><td style="text-align:left;">温坎阳、补乾阳</td></tr><tr><td style="text-align:left;"><strong>人参</strong></td><td style="text-align:left;">坤宫</td><td style="text-align:left;">补坤土</td></tr><tr><td style="text-align:left;"><strong>茯苓</strong></td><td style="text-align:left;">坤宫+坎宫</td><td style="text-align:left;">泻坤湿+利坎水</td></tr><tr><td style="text-align:left;"><strong>干姜</strong></td><td style="text-align:left;">坤宫+艮宫</td><td style="text-align:left;">温坤土、暖艮胃</td></tr><tr><td style="text-align:left;"><strong>桂枝</strong></td><td style="text-align:left;">震宫+坎宫</td><td style="text-align:left;">升震木、温水寒</td></tr><tr><td style="text-align:left;"><strong>龙骨</strong></td><td style="text-align:left;">离宫+坎宫</td><td style="text-align:left;">降离火、潜坎阳</td></tr><tr><td style="text-align:left;"><strong>牡蛎</strong></td><td style="text-align:left;">离宫+坎宫</td><td style="text-align:left;">降离火、敛坎精</td></tr><tr><td style="text-align:left;"><strong>当归</strong></td><td style="text-align:left;">震宫+坤宫</td><td style="text-align:left;">养震血、润坤土</td></tr><tr><td style="text-align:left;"><strong>白芍</strong></td><td style="text-align:left;">震宫+兑宫</td><td style="text-align:left;">敛震阴、润兑金</td></tr><tr><td style="text-align:left;"><strong>熟地</strong></td><td style="text-align:left;">坎宫+坤宫</td><td style="text-align:left;">补坎水、滋坤阴</td></tr><tr><td style="text-align:left;"><strong>柴胡</strong></td><td style="text-align:left;">巽宫+震宫</td><td style="text-align:left;">疏巽木、升震阳</td></tr><tr><td style="text-align:left;"><strong>麦冬</strong></td><td style="text-align:left;">兑宫+离宫</td><td style="text-align:left;">润兑金、清离火</td></tr><tr><td style="text-align:left;"><strong>黄柏</strong></td><td style="text-align:left;">坎宫</td><td style="text-align:left;">清坎热（湿热）</td></tr><tr><td style="text-align:left;"><strong>泽泻</strong></td><td style="text-align:left;">坎宫</td><td style="text-align:left;">利坎水</td></tr><tr><td style="text-align:left;"><strong>丹皮</strong></td><td style="text-align:left;">离宫+震宫</td><td style="text-align:left;">清离血、疏震瘀</td></tr></tbody></table><h3 id="患者处方的八宫分析" tabindex="-1">患者处方的八宫分析 <a class="header-anchor" href="#患者处方的八宫分析" aria-label="Permalink to &quot;患者处方的八宫分析&quot;">​</a></h3><p><strong>温潜黄芽天魂汤</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:left;">归宫</th><th style="text-align:left;">作用</th></tr></thead><tbody><tr><td style="text-align:left;">人参9g</td><td style="text-align:left;">坤</td><td style="text-align:left;">补脾土</td></tr><tr><td style="text-align:left;">炙甘草6g</td><td style="text-align:left;">坤</td><td style="text-align:left;">和中</td></tr><tr><td style="text-align:left;">茯苓15g</td><td style="text-align:left;">坤+坎</td><td style="text-align:left;">泻湿</td></tr><tr><td style="text-align:left;">干姜10g</td><td style="text-align:left;">坤+艮</td><td style="text-align:left;">温中</td></tr><tr><td style="text-align:left;">桂枝9g</td><td style="text-align:left;">震+坎</td><td style="text-align:left;">⭐ 提升坎水上达震宫</td></tr><tr><td style="text-align:left;">附子9g</td><td style="text-align:left;">坎+乾</td><td style="text-align:left;">⭐ 核心药：温坎水</td></tr><tr><td style="text-align:left;">白芍10g</td><td style="text-align:left;">震+兑</td><td style="text-align:left;">敛震阳</td></tr><tr><td style="text-align:left;">当归10g</td><td style="text-align:left;">震+坤</td><td style="text-align:left;">养肝血</td></tr><tr><td style="text-align:left;">龙骨15g</td><td style="text-align:left;">离+坎</td><td style="text-align:left;">⭐ 降离火入坎水</td></tr><tr><td style="text-align:left;">牡蛎15g</td><td style="text-align:left;">离+坎</td><td style="text-align:left;">同上</td></tr><tr><td style="text-align:left;">泽泻9g</td><td style="text-align:left;">坎</td><td style="text-align:left;">利坎水湿</td></tr><tr><td style="text-align:left;">丹皮9g</td><td style="text-align:left;">离+震</td><td style="text-align:left;">清离热+疏震瘀</td></tr><tr><td style="text-align:left;">黄柏6g</td><td style="text-align:left;">坎</td><td style="text-align:left;">清坎湿热</td></tr><tr><td style="text-align:left;">牛膝10g</td><td style="text-align:left;">坎</td><td style="text-align:left;">引火下行归坎</td></tr></tbody></table><p><strong>八宫覆盖</strong>：坤+坎+震+离 = <strong>四宫同治——这正是京房&quot;八宫调气&quot;的核心思路。</strong></p><hr><h2 id="五、八宫卦气养生日用" tabindex="-1">五、八宫卦气养生日用 <a class="header-anchor" href="#五、八宫卦气养生日用" aria-label="Permalink to &quot;五、八宫卦气养生日用&quot;">​</a></h2><p><strong>每日按八宫顺序养护</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">时间</th><th style="text-align:left;">宫</th><th style="text-align:left;">怎么做</th></tr></thead><tbody><tr><td style="text-align:left;">晨起5-7点</td><td style="text-align:left;"><strong>乾宫（金）</strong></td><td style="text-align:left;">深呼吸，开肺气</td></tr><tr><td style="text-align:left;">上午7-9点</td><td style="text-align:left;"><strong>兑宫（金）</strong></td><td style="text-align:left;">喝温水润口鼻</td></tr><tr><td style="text-align:left;">上午9-11点</td><td style="text-align:left;"><strong>坤宫（土）</strong></td><td style="text-align:left;">⭐ <strong>吃早餐，养脾胃</strong></td></tr><tr><td style="text-align:left;">上午11-1点</td><td style="text-align:left;"><strong>离宫（火）</strong></td><td style="text-align:left;">午休养心</td></tr><tr><td style="text-align:left;">下午1-3点</td><td style="text-align:left;"><strong>巽宫（木）</strong></td><td style="text-align:left;">疏肝气（轻拍胆经）</td></tr><tr><td style="text-align:left;">下午3-5点</td><td style="text-align:left;"><strong>坎宫（水）</strong></td><td style="text-align:left;">喝水排浊</td></tr><tr><td style="text-align:left;">下午5-7点</td><td style="text-align:left;"><strong>艮宫（土）</strong></td><td style="text-align:left;">胃休息，晚餐清淡</td></tr><tr><td style="text-align:left;">晚上7-9点</td><td style="text-align:left;"><strong>震宫（木）</strong></td><td style="text-align:left;">泡脚、放松</td></tr><tr><td style="text-align:left;">晚上9-11点</td><td style="text-align:left;"><strong>乾宫+坤宫</strong></td><td style="text-align:left;">静坐、准备入睡</td></tr></tbody></table><hr><p><em>八宫卦气与五脏六腑的完整对应体系完。京房易是中医&quot;五运六气&quot;和&quot;脏腑辨证&quot;的易学源头之一，值得深入研习。</em></p>`,87)])])}const h=e(a,[["render",d]]);export{f as __pageData,h as default};
